get skippedTests() {
  return this._tests.filter(test => test.state === 'skipped' || test.state === 'pending')
}

simplify() {
  return {
    hasFailed: this.hasFailed,
    stats: this.stats,
    duration: this.duration,
    tests: this._tests.map(test => serializeTest(test)),
    failures: this._failures,
