      print(`  ${colors.red.bold(figures.cross)} ${maskData(test.title)} ${colors.grey(`in ${test.duration}ms`)}`)
    },
    /**
     * @param {Mocha.Test} test
     */
    skipped(test) {
      print(`  ${colors.yellow.bold('S')} ${maskData(test.title)}`)
    },
  },

  /** @namespace */
  scenario: {
    /**
     * @param {Mocha.Test} test
     */

    started(test) {
      if (outputLevel < 1) return
      print(`  ${colors.dim.bold('Scenario()')}`)
    },

    /**
     * @param {Mocha.Test} test
     */
    passed(test) {
      print(`  ${colors.green.bold(`${figures.tick} OK`)} ${colors.grey(`in ${test.duration}ms`)}`)
      print()
    },
    /**
     * @param {Mocha.Test} test
     */
    failed(test) {
      print(`  ${colors.red.bold(`${figures.cross} FAILED`)} ${colors.grey(`in ${test.duration}ms`)}`)
      print()
    },
  },

  hook: {
    started(hook) {
      if (outputLevel < 1) return
      print(`  ${colors.dim.bold(maskData(hook.toCode()))}`)
    },
    passed(hook) {
      if (outputLevel < 1) return
      print()
    },
    failed(hook) {
      if (outputLevel < 1) return
      print(`  ${colors.red.bold(maskData(hook.toCode()))}`)
    },
  },

  /**
   *
   * Print a text in console log
   * @param {string} message
   * @param {string} [color]
   */
  say(message, color = 'cyan') {
    if (colors[color] === undefined) {
      color = 'cyan'
    }
    if (outputLevel >= 1) print(`   ${colors[color].bold(message)}`)
  },

  /**
   * @param {number} passed
   * @param {number} failed
   * @param {number} skipped
   * @param {number|string} duration
   */
  result(passed, failed, skipped, duration, failedHooks = 0) {
    let style = colors.bgGreen
    let msg = ` ${passed || 0} passed`
    let status = style.bold('  OK ')
    if (failed) {
      style = style.bgRed
      status = style.bold('  FAIL ')
      msg += `, ${failed} failed`
    }

    if (failedHooks > 0) {
      style = style.bgRed
      status = style.bold('  FAIL ')
      msg += `, ${failedHooks} failedHooks`
    }
    status += style.grey(' |')

    if (skipped) {
      if (!failed) style = style.bgYellow
      msg += `, ${skipped} skipped`
    }
    msg += '  '
    print(status + style(msg) + colors.grey(` // ${duration}`))
  },
}

function print(...msg) {
  if (outputProcess) {
    msg.unshift(outputProcess)
  }
  if (!newline) {
    console.log()
    newline = true
  }

  console.log.apply(this, msg)
}

function truncate(msg, gap = 0) {
  if (msg.indexOf('\n') > 0 || outputLevel >= 3) {
    return msg // don't cut multi line steps or on verbose log level
  }
  const width = (process.stdout.columns || 200) - gap - 4
  if (msg.length > width) {
    msg = msg.substr(0, width - 1) + figures.ellipsis
  }
  return msg
}

function isMaskedData() {
  return getMaskSensitiveDataConfig().enabled
}

function maskData(msg) {
  if (typeof msg !== 'string' || msg.trim().length === 0 || !isMaskedData()) return msg
  return maskSensitiveData(msg, getMaskSensitiveDataConfig().patterns)
}

function getMaskSensitiveDataConfig() {
  const config = global.maskSensitiveData

  if (!config) return DEFAULT_MASK_SENSITIVE_DATA_CONFIG

  if (config === true) {
    return {
      ...DEFAULT_MASK_SENSITIVE_DATA_CONFIG,
      enabled: true,
    }
  }

  if (Array.isArray(config)) {
    return {
      enabled: true,
      patterns: config,
    }
  }

  if (typeof config === 'object') {
    return {
      enabled: config.enabled !== false,
      patterns: config.patterns || [],
    }
  }

  return DEFAULT_MASK_SENSITIVE_DATA_CONFIG
}

